import React, { useEffect, useState } from "react";
import axios from "axios";

function Ranking() {
  const [data, setData] = useState([]);

  useEffect(() => {
    axios.get("http://127.0.0.1:8000/analytics")
      .then(res => setData(res.data));
  }, []);

  return (
    <div>
      <h2>Ranking</h2>
      {data.map((d, i) => (
        <div key={i}>
          Rank {d.rank} → {d.symbol}
        </div>
      ))}
    </div>
  );
}

export default Ranking;
